refsection.programlisting:

load(GROCERDIR+'/data/bdhenderic.dat') ;

bounds('1964q3','1989q2')
// column HE in table 9 of Hendry and Krozlig paper
r=ols('delts(lm1-lp)','lagts(lm1-lp-ly)','delts(lp)','rnet','delts(lagts(lm1-lp-ly))','cte')

predfailin(r,50)
// Example taken from predfailin_d. The example provides the predictive failure test with a break at observation # 50
// for Hendry and Ericsson equation # 6, whose results have been stored in tlist r.
